import tensorflow as tf

def reward_model_loss(chosen_rewards: list, rejected_rewards: list, margin: float = 0.0) -> dict:
    """
    Compute reward model loss from pairwise human preferences.

    Args:
        chosen_rewards: Reward scores for preferred responses
        rejected_rewards: Reward scores for non-preferred responses
        margin: Minimum desired gap between chosen and rejected scores

    Returns:
        Dictionary with 'loss' (float) and 'accuracy' (float)
    """
    if not chosen_rewards:
        return {'loss': 0.0, 'accuracy': 0.0}

    chosen = tf.constant(chosen_rewards, dtype=tf.float64)
    rejected = tf.constant(rejected_rewards, dtype=tf.float64)

    diff = chosen - rejected - margin  # (n,)

    # tf.math.softplus(-diff) = log(1 + exp(-diff)) = -log(sigmoid(diff))
    # This is TensorFlow's stable implementation.
    loss_per_pair = tf.math.softplus(-diff)
    loss = round(float(tf.reduce_mean(loss_per_pair).numpy()), 4)

    accuracy = round(float(tf.reduce_mean(
        tf.cast(chosen > rejected, tf.float64)
    ).numpy()), 4)

    return {'loss': loss, 'accuracy': accuracy}


# ---- Production variant: Keras-compatible loss class ----

class PairwiseRewardLoss(tf.keras.losses.Loss):
    """
    Keras Loss subclass for reward model training.
    Usage: model.compile(loss=PairwiseRewardLoss(margin=0.5))
    chosen and rejected are concatenated along axis=0 by the caller;
    pass them as a stacked (2*B,) tensor split internally.
    """
    def __init__(self, margin: float = 0.0, **kwargs):
        super().__init__(**kwargs)
        self.margin = margin

    def call(self, chosen_rewards: tf.Tensor, rejected_rewards: tf.Tensor) -> tf.Tensor:
        diff = chosen_rewards - rejected_rewards - self.margin
        return tf.reduce_mean(tf.math.softplus(-diff))

    def get_config(self):
        return {**super().get_config(), 'margin': self.margin}
